function normalize(text:string){return text.replace(/^\uFEFF/,'').replace(/\r\n/g,'\n').replace(/\r/g,'\n');}
function hashText(text:string){return createHash('sha256').update(normalize(text),'utf8').digest('hex');}
function readText(path:string){return readFileSync(path,'utf8');}
function decode(data:string){return gunzipSync(Buffer.from(data,'base64')).toString('utf8');}
function isRoot(dir:string){return existsSync(join(dir,'package.json'))&&existsSync(join(dir,'shared','src','index.ts'))&&existsSync(join(dir,'server','src','rooms','Drop8Room.ts'))&&existsSync(join(dir,'client','src','GameScene.ts'));}
function ancestors(start:string){const result:string[]=[];let current=resolve(start);for(let i=0;i<12;i++){if(!result.includes(current))result.push(current);const parent=dirname(current);if(parent===current)break;current=parent;}return result;}
function findRoot(){const scriptDir=dirname(fileURLToPath(import.meta.url));for(const candidate of [...ancestors(process.cwd()),...ancestors(scriptDir)])if(isRoot(candidate))return candidate;throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 패치 파일을 프로젝트 루트에서 실행하세요.');}
function stamp(){return new Date().toISOString().replace(/[:.]/g,'-');}
