function mergeThreeWay(current:string,base:string,patched:string,relative:string,tempRoot:string){
  const safe=relative.replace(/[\\/:*?"<>|]/g,'_');
  const currentPath=join(tempRoot,`${safe}.current`),basePath=join(tempRoot,`${safe}.base`),patchedPath=join(tempRoot,`${safe}.patched`);
  writeFileSync(currentPath,normalize(current),'utf8');writeFileSync(basePath,normalize(base),'utf8');writeFileSync(patchedPath,normalize(patched),'utf8');
  const result=spawnSync('git',['merge-file','-p','--diff3','--',currentPath,basePath,patchedPath],{encoding:'utf8',maxBuffer:64*1024*1024,windowsHide:true});
  if(result.error)throw new Error(`${relative}: Git 3-way merge 실행 실패: ${result.error.message}`);
  if(result.status===1){const conflictPath=join(tempRoot,`${safe}.CONFLICT.txt`);writeFileSync(conflictPath,result.stdout||'','utf8');throw new Error(`${relative}: 현재 수동 수정과 Refactor 016 수정이 같은 코드 구간에서 충돌했습니다. 원본은 변경하지 않았습니다.`);}
  if(result.status!==0)throw new Error(`${relative}: Git 3-way merge 실패 (exit=${result.status}): ${String(result.stderr||'').trim()}`);
  const merged=normalize(result.stdout||'');
  if(merged.includes('<<<<<<<')||merged.includes('=======')||merged.includes('>>>>>>>'))throw new Error(`${relative}: merge 충돌 표식이 감지되었습니다.`);
  return merged;
}

function importLocals(text:string){
  const locals:string[]=[];
  const named=/import\s+(?:type\s+)?\{([\s\S]*?)\}\s+from\s+['"][^'"]+['"]/g;
  for(const match of text.matchAll(named))for(const raw of match[1].split(',')){const item=raw.trim().replace(/^type\s+/,'');if(!item)continue;const parts=item.split(/\s+as\s+/);locals.push((parts[1]??parts[0]).trim());}
  const defaults=/^import\s+(?!type\b)([A-Za-z_$][\w$]*)\s*(?:,|from)/gm;
  for(const match of text.matchAll(defaults))locals.push(match[1]);
  const namespaces=/^import\s+\*\s+as\s+([A-Za-z_$][\w$]*)\s+from/gm;
  for(const match of text.matchAll(namespaces))locals.push(match[1]);
  return locals;
}
function validateDuplicateDeclarations(text:string,file:string){
  const names=[...importLocals(text)];
  const declarations=/^(?:export\s+)?(?:declare\s+)?(?:const|let|var|function|class|interface|type|enum)\s+([A-Za-z_$][\w$]*)/gm;
  for(const match of text.matchAll(declarations))names.push(match[1]);
  const seen=new Set<string>();
  for(const name of names){if(seen.has(name))throw new Error(`${file}: 최상위 식별자 '${name}' 중복 선언`);seen.add(name);}
}
function validateRelativeImports(root:string,relative:string,text:string){
  const pattern=/(?:from\s+|import\s*\()\s*['"](\.[^'"]+)['"]/g;
  for(const match of text.matchAll(pattern)){
    const spec=match[1];let target=resolve(dirname(join(root,relative)),spec);
    const candidates=[target];if(extname(target)==='.js')candidates.push(target.slice(0,-3)+'.ts');if(!extname(target))candidates.push(target+'.ts',target+'.tsx',join(target,'index.ts'));
    if(!candidates.some((candidate)=>existsSync(candidate)))throw new Error(`${relative}: 상대 import 확인 실패 '${spec}'`);
  }
}
function getText(root:string,planned:Map<string,string>,relative:string){return planned.get(relative)??readText(join(root,relative));}
function captureCriticalShared(text:string){
  const patterns:{name:string,re:RegExp}[]=[
    {name:'bazooka projectileSpeed',re:/bazooka:\{[^\n]*projectileSpeed:(\d+(?:\.\d+)?)/},
    {name:'supply triggerZoneStage',re:/triggerZoneStage:(\d+)/},
    {name:'supply weights',re:/bazookaWeight:(\d+),flamethrowerWeight:(\d+)/},
    {name:'flamethrower tick damage',re:/playerDamagePerTick:(\d+),vehicleDamagePerTick:(\d+),fuelPerTick:(\d+)/},
    {name:'bazooka vehicle damage',re:/directVehicleDamage:(\d+),maxSplashVehicleDamage:(\d+),minSplashVehicleDamage:(\d+),structureDamage:(\d+)/},
  ];
  return patterns.map(({name,re})=>{const m=re.exec(text);if(!m)throw new Error(`shared/src/index.ts: 기존 핵심 설정 '${name}'을 찾지 못했습니다.`);return {name,value:m.slice(1).join('|')};});
}
